const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const calculateComponentPremium = (type: string, count: number): number =>
  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);

export function processScenario(scenario: Scenario): ScenarioOutput {
  const results = scenario.steps.map((step) => {
    let basePremium = 0;

    const componentCounts = new Map<string, number>();
    for (const item of step.items) {
      if (COMPONENT_TYPES.has(item.type)) {
        componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
      } else {
        const itemBase = BASE_PREMIUMS[item.type] ?? 0;
        let itemPremium = itemBase;
        if (item.cursed) {
          itemPremium += itemBase * 0.5;
        }
        if (item.enchantment >= 5) {
          itemPremium += itemBase * 0.3;
        }
        basePremium += itemPremium;
      }
    }

    for (const [type, count] of componentCounts) {
      basePremium += calculateComponentPremium(type, count);
    }

    const policyPremium = basePremium + basePremium * 0.1;
    const premium = Math.ceil(policyPremium) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

