1	interface Item {
2	  type: string;
3	  material: string;
4	  enchantment: number;
5	  cursed: boolean;
6	}
7	
8	interface Step {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Scenario {
14	  customer: { yearsWithMHPCO: number };
15	  steps: Step[];
16	}
17	
18	interface QuoteResult {
19	  premium: number;
20	}
21	
22	interface ScenarioOutput {
23	  results: QuoteResult[];
24	}
25	
26	const PROCESSING_FEE = 5;
27	const CURSED_SURCHARGE_RATE = 0.5;
28	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
29	const HIGH_ENCHANTMENT_THRESHOLD = 5;
30	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
31	
32	const BASE_PREMIUMS: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
42	const BLOCK_SIZE = 3;
43	const BLOCK_PREMIUM = 60;
44	
45	const calculateComponentPremium = (type: string, count: number): number =>
46	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
47	
48	const calculateItemPremium = (item: Item): number => {
49	  const base = BASE_PREMIUMS[item.type] ?? 0;
50	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
51	  const enchantmentSurcharge =
52	    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
53	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
54	      : 0;
55	  return base + cursedSurcharge + enchantmentSurcharge;
56	};
57	
58	export function processScenario(scenario: Scenario): ScenarioOutput {
59	  const results = scenario.steps.map((step) => {
60	    const componentCounts = new Map<string, number>();
61	    let mainItemsPremium = 0;
62	
63	    for (const item of step.items) {
64	      if (COMPONENT_TYPES.has(item.type)) {
65	        componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
66	      } else {
67	        mainItemsPremium += calculateItemPremium(item);
68	      }
69	    }
70	
71	    let basePremium = mainItemsPremium;
72	    for (const [type, count] of componentCounts) {
73	      basePremium += calculateComponentPremium(type, count);
74	    }
75	
76	    const policyPremium = basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
77	    const premium = Math.ceil(policyPremium) + PROCESSING_FEE;
78	    return { premium };
79	  });
80	  return { results };
81	}
